// Copies the MediaPipe pose-estimation WASM runtime into public/ (self-hosted,
// same rationale as ffmpeg's core: same-origin, no CDN/version-drift risk) and
// downloads the pose landmarker model file. Neither is committed to git —
// both are regenerated by `npm install` (see package.json "postinstall").
const fs = require("fs");
const path = require("path");
const https = require("https");

const wasmSrcDir = path.join(__dirname, "..", "node_modules", "@mediapipe", "tasks-vision", "wasm");
const destDir = path.join(__dirname, "..", "public", "mediapipe");
const wasmDestDir = path.join(destDir, "wasm");

const MODEL_URL = "https://storage.googleapis.com/mediapipe-models/pose_landmarker/pose_landmarker_full/float16/latest/pose_landmarker_full.task";
const modelDest = path.join(destDir, "pose_landmarker_full.task");

function download(url, dest) {
  return new Promise((resolve, reject) => {
    const file = fs.createWriteStream(dest);
    https.get(url, (res) => {
      if (res.statusCode !== 200) {
        reject(new Error(`Failed to download ${url}: HTTP ${res.statusCode}`));
        return;
      }
      res.pipe(file);
      file.on("finish", () => file.close(resolve));
    }).on("error", (err) => {
      fs.unlink(dest, () => {});
      reject(err);
    });
  });
}

async function main() {
  if (!fs.existsSync(wasmSrcDir)) {
    console.warn("[setup-pose-assets] @mediapipe/tasks-vision wasm not found, skipping (pose estimation will be unavailable)");
    return;
  }

  fs.mkdirSync(wasmDestDir, { recursive: true });
  for (const file of fs.readdirSync(wasmSrcDir)) {
    fs.copyFileSync(path.join(wasmSrcDir, file), path.join(wasmDestDir, file));
  }
  console.log("[setup-pose-assets] copied MediaPipe wasm runtime to public/mediapipe/wasm/");

  if (fs.existsSync(modelDest) && fs.statSync(modelDest).size > 1_000_000) {
    console.log("[setup-pose-assets] pose_landmarker_full.task already present, skipping download");
    return;
  }

  try {
    console.log("[setup-pose-assets] downloading pose_landmarker_full.task (~9MB)...");
    await download(MODEL_URL, modelDest);
    console.log("[setup-pose-assets] downloaded pose_landmarker_full.task to public/mediapipe/");
  } catch (err) {
    console.warn("[setup-pose-assets] could not download pose model (pose estimation will be unavailable at runtime):", err.message);
  }
}

main();
